[{"id":"ewchome01","elType":"section","isInner":false,"settings":{},"elements":[{"id":"ewchome02","elType":"column","isInner":false,"settings":{"_column_size":100},"elements":[{"id":"ewchome03","elType":"widget","widgetType":"html","settings":{"html":"<style>
  body.page-id-1968 .site-header,
  body.page-id-1968 .page-header,
  body.page-id-1968 footer.site-footer {
    display: none !important;
  }

  body.page-id-1968 #content.site-main {
    max-width: none;
    width: 100%;
    margin: 0;
  }

  .ewc-home-v2 {
    --ewc-bg: #05070b;
    --ewc-surface: rgba(255, 255, 255, 0.06);
    --ewc-surface-strong: rgba(255, 255, 255, 0.1);
    --ewc-border: rgba(255, 255, 255, 0.12);
    --ewc-text: #f5f7fb;
    --ewc-muted: #a2adc0;
    --ewc-soft: #d6dff0;
    --ewc-accent: #8ab6ff;
    --ewc-accent-2: #6bf1d3;
    --ewc-shadow: 0 32px 80px rgba(0, 0, 0, 0.35);
    background:
      radial-gradient(circle at top left, rgba(68, 98, 255, 0.25), transparent 38%),
      radial-gradient(circle at top right, rgba(59, 191, 255, 0.18), transparent 32%),
      linear-gradient(180deg, #06080d 0%, #05070b 46%, #090d16 100%);
    color: var(--ewc-text);
    width: 100vw;
    margin: 0 0 0 calc(50% - 50vw);
    overflow: hidden;
  }

  .ewc-home-v2,
  .ewc-home-v2 * {
    box-sizing: border-box;
  }

  .ewc-home-v2 a {
    color: inherit;
    text-decoration: none;
  }

  .ewc-shell-nav {
    width: min(1240px, calc(100% - 56px));
    margin: 0 auto;
  }

  .ewc-shell {
    width: min(1180px, calc(100% - 40px));
    margin: 0 auto;
  }

  .ewc-topbar {
    padding-top: 24px;
  }

  .ewc-nav-island {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 18px;
    padding: 14px 18px 14px 20px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: rgba(10, 15, 26, 0.84);
    box-shadow: 0 30px 80px rgba(0, 0, 0, 0.36);
    backdrop-filter: blur(22px);
    font-family: "Poppins", "Helvetica Neue", Arial, sans-serif;
  }

  @keyframes ewcBrandPulse {
    0%,
    100% {
      transform: scale(1);
      opacity: 0.88;
      box-shadow: 0 0 18px rgba(124, 240, 211, 0.2);
    }
    50% {
      transform: scale(1.08);
      opacity: 1;
      box-shadow: 0 0 26px rgba(124, 240, 211, 0.32);
    }
  }

  .ewc-nav-panel {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 18px;
    flex: 1 1 auto;
    min-width: 0;
  }

  .ewc-brand {
    display: inline-flex;
    align-items: center;
    gap: 12px;
    min-height: 48px;
    color: var(--ewc-soft);
    font-size: 14px;
    font-weight: 700;
    line-height: 1;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    white-space: nowrap;
  }

  .ewc-brand-mark {
    width: 12px;
    height: 12px;
    flex: 0 0 auto;
    border-radius: 999px;
    background: linear-gradient(135deg, var(--ewc-accent) 0%, var(--ewc-accent-2) 100%);
    box-shadow: 0 0 24px rgba(124, 240, 211, 0.26);
    animation: ewcBrandPulse 2.8s ease-in-out infinite;
  }

  .ewc-nav-links {
    display: inline-flex;
    align-items: center;
    gap: 30px;
    flex-wrap: wrap;
    justify-content: center;
  }

  .ewc-nav-links a {
    display: inline-flex;
    align-items: center;
    min-height: 48px;
    color: var(--ewc-muted);
    font-size: 13px;
    font-weight: 600;
    line-height: 1;
    letter-spacing: 0.08em;
    text-transform: uppercase;
  }

  .ewc-nav-links a:hover {
    color: var(--ewc-text);
  }

  .ewc-nav-cta {
    flex: 0 0 auto;
    align-self: center;
  }

  .ewc-nav-panel-head {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
    flex: 0 0 auto;
  }

  .ewc-nav-overlay,
  .ewc-nav-close {
    display: none;
  }

  .ewc-nav-toggle {
    display: none;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 5px;
    width: 48px;
    height: 48px;
    padding: 0;
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.05);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
    color: var(--ewc-text);
    cursor: pointer;
    appearance: none;
    -webkit-appearance: none;
    -webkit-tap-highlight-color: transparent;
    outline: none;
    transition: background 180ms ease, border-color 180ms ease, transform 180ms ease;
  }

  .ewc-nav-toggle:hover {
    transform: translateY(-1px);
  }

  .ewc-nav-toggle:focus,
  .ewc-nav-toggle:focus-visible {
    outline: none;
    border-color: rgba(198, 221, 255, 0.26);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04), 0 0 0 3px rgba(118, 140, 175, 0.18);
  }

  .ewc-nav-toggle span {
    display: block;
    width: 18px;
    height: 2px;
    border-radius: 999px;
    background: currentColor;
    transition: transform 180ms ease, opacity 180ms ease;
  }

  .ewc-nav-island.ewc-nav-open .ewc-nav-toggle span:first-child {
    transform: translateY(3.5px) rotate(45deg);
  }

  .ewc-nav-island.ewc-nav-open .ewc-nav-toggle span:last-child {
    transform: translateY(-3.5px) rotate(-45deg);
  }

  .ewc-nav-island.ewc-nav-open .ewc-nav-toggle {
    background: rgba(118, 140, 175, 0.18);
    border-color: rgba(198, 221, 255, 0.24);
  }

  .ewc-button,
  .ewc-button-small {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 999px;
    border: 1px solid transparent;
    font-size: 15px;
    font-weight: 700;
    letter-spacing: 0.01em;
    transition: transform 180ms ease, background 180ms ease, border-color 180ms ease;
  }

  .ewc-button:hover,
  .ewc-button-small:hover {
    transform: translateY(-1px);
  }

  .ewc-button {
    min-height: 52px;
    padding: 0 24px;
  }

  .ewc-button-small {
    min-height: 48px;
    padding: 0 20px;
    font-size: 14px;
    font-family: "Poppins", "Helvetica Neue", Arial, sans-serif;
    line-height: 1;
  }

  .ewc-button-primary {
    background: linear-gradient(135deg, #7086a7 0%, #4d637f 100%);
    border-color: rgba(198, 221, 255, 0.18);
    color: #f8fbff;
    box-shadow: 0 14px 28px rgba(69, 89, 118, 0.28);
  }

  .ewc-button-primary.ewc-button-accent {
    background: linear-gradient(135deg, #77e8d2 0%, #4fcab5 100%);
    border-color: rgba(107, 241, 211, 0.24);
    color: #07121d;
    box-shadow: 0 16px 30px rgba(56, 140, 126, 0.24);
  }

  .ewc-button-primary.ewc-button-accent:hover {
    background: linear-gradient(135deg, #84eed9 0%, #5ad5c0 100%);
  }

  .ewc-nav-island .ewc-nav-cta.ewc-button-primary {
    background: linear-gradient(180deg, #ffffff 0%, #e7eef7 100%);
    border-color: rgba(255, 255, 255, 0.74);
    color: #08111d;
    box-shadow: 0 18px 34px rgba(4, 8, 14, 0.24), inset 0 1px 0 rgba(255, 255, 255, 0.78);
    transition: transform 220ms ease, background 240ms ease, border-color 240ms ease, color 240ms ease, box-shadow 240ms ease;
  }

  .ewc-nav-island .ewc-nav-cta.ewc-button-primary:hover {
    background: linear-gradient(135deg, #77e8d2 0%, #4fcab5 100%);
    border-color: rgba(107, 241, 211, 0.3);
    color: #f8fbff;
    box-shadow: 0 18px 34px rgba(56, 140, 126, 0.28);
  }

  .ewc-button-secondary {
    background: linear-gradient(180deg, rgba(29, 39, 58, 0.96) 0%, rgba(16, 23, 36, 0.96) 100%);
    border-color: rgba(255, 255, 255, 0.16);
    color: #f5f7fb;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.05);
  }

  .ewc-section {
    padding: 84px 0;
  }

  .ewc-eyebrow {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    padding: 10px 16px;
    border: 1px solid var(--ewc-border);
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    color: var(--ewc-soft);
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 0.14em;
    text-transform: uppercase;
  }

  #process .ewc-eyebrow,
  .ewc-credibility-copy .ewc-eyebrow,
  .ewc-custom-analysis .ewc-eyebrow,
  .ewc-final-cta .ewc-eyebrow {
    border-color: rgba(107, 241, 211, 0.22);
    background: rgba(107, 241, 211, 0.08);
    color: #cff8ef;
  }

  .ewc-hero {
    padding: 72px 0 72px;
    display: grid;
    grid-template-columns: minmax(0, 1.08fr) minmax(0, 0.92fr);
    gap: 36px;
    align-items: center;
  }

  .ewc-hero h1,
  .ewc-section h2,
  .ewc-section h3 {
    margin: 0;
    color: var(--ewc-text);
    line-height: 1.02;
    letter-spacing: -0.04em;
  }

  .ewc-hero h1 {
    margin-top: 22px;
    font-size: clamp(46px, 7vw, 84px);
    max-width: 12ch;
  }

  .ewc-lead {
    margin: 22px 0 0;
    max-width: 60ch;
    color: var(--ewc-muted);
    font-size: clamp(18px, 2vw, 22px);
    line-height: 1.6;
  }

  .ewc-actions {
    display: flex;
    flex-wrap: wrap;
    gap: 14px;
    margin-top: 30px;
  }

  .ewc-proof-inline {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 24px;
  }

  .ewc-proof-pill,
  .ewc-pill {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 10px 14px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(255, 255, 255, 0.08);
    color: var(--ewc-soft);
    font-size: 13px;
    line-height: 1;
  }

  .ewc-proof-pill strong,
  .ewc-stat strong,
  .ewc-card strong,
  .ewc-quote strong {
    color: var(--ewc-text);
  }

  #proof .ewc-stat:nth-child(-n + 2) strong {
    color: var(--ewc-accent-2);
    text-shadow: 0 0 18px rgba(107, 241, 211, 0.18);
  }

  .ewc-hero-card,
  .ewc-card,
  .ewc-quote,
  .ewc-price-card,
  .ewc-disclaimer,
  .ewc-final-cta {
    position: relative;
    border: 1px solid var(--ewc-border);
    border-radius: 28px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.09) 0%, rgba(255, 255, 255, 0.04) 100%);
    box-shadow: var(--ewc-shadow);
    backdrop-filter: blur(20px);
  }

  .ewc-hero-card {
    padding: 18px;
  }

  .ewc-hero-media {
    overflow: hidden;
    border-radius: 22px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: #0d1320;
  }

  .ewc-hero-media img {
    display: block;
    width: 100%;
    height: auto;
  }

  .ewc-credibility-media img {
    display: block;
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .ewc-hero-meta {
    display: flex;
    justify-content: space-between;
    gap: 16px;
    flex-wrap: wrap;
    padding: 18px 6px 8px;
  }

  .ewc-hero-meta span {
    display: block;
    font-size: 12px;
    color: var(--ewc-muted);
    text-transform: uppercase;
    letter-spacing: 0.12em;
  }

  .ewc-hero-meta strong {
    display: block;
    margin-top: 6px;
    font-size: 16px;
    font-weight: 700;
    color: var(--ewc-text);
  }

  .ewc-stats-grid,
  .ewc-card-grid,
  .ewc-proof-grid,
  .ewc-quote-grid,
  .ewc-pricing-grid {
    display: grid;
    gap: 18px;
  }

  .ewc-stats-grid {
    grid-template-columns: repeat(4, minmax(0, 1fr));
  }

  .ewc-stat {
    padding: 26px 24px;
    border-radius: 24px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: rgba(255, 255, 255, 0.04);
  }

  .ewc-stat strong {
    display: block;
    font-size: clamp(28px, 4vw, 42px);
    letter-spacing: -0.05em;
  }

  .ewc-stat span {
    display: block;
    margin-top: 10px;
    color: var(--ewc-muted);
    line-height: 1.5;
  }

  .ewc-section-head {
    display: grid;
    gap: 18px;
    margin-bottom: 28px;
  }

  .ewc-section-head h2 {
    font-size: clamp(34px, 5vw, 58px);
    max-width: 12ch;
  }

  .ewc-section-head p {
    margin: 0;
    max-width: 62ch;
    color: var(--ewc-muted);
    font-size: 18px;
    line-height: 1.7;
  }

  .ewc-card-grid {
    grid-template-columns: repeat(5, minmax(0, 1fr));
  }

  #inside .ewc-card-grid {
    align-items: stretch;
    grid-auto-rows: 1fr;
    gap: 18px;
  }

  .ewc-proof-grid {
    grid-template-columns: repeat(4, minmax(0, 1fr));
  }

  .ewc-card,
  .ewc-proof-card,
  .ewc-quote {
    padding: 26px 24px;
  }

  #inside .ewc-card {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    min-height: 100%;
    padding: 28px 24px;
    gap: 14px;
    border-radius: 24px;
  }

  .ewc-stats-grid .ewc-stat,
  .ewc-card-grid .ewc-card,
  .ewc-proof-grid .ewc-proof-card,
  .ewc-quote-grid .ewc-quote,
  .ewc-price-card {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    height: 100%;
  }

  .ewc-card h3,
  .ewc-proof-card h3,
  .ewc-price-card h3,
  .ewc-quote h3 {
    font-size: 22px;
    line-height: 1.15;
  }

  #inside .ewc-card h3 {
    width: 100%;
    margin: 0;
    min-height: 2.35em;
    display: flex;
    align-items: flex-start;
  }

  .ewc-card p,
  .ewc-proof-card p,
  .ewc-price-card p,
  .ewc-quote p {
    margin: 14px 0 0;
    color: var(--ewc-muted);
    line-height: 1.7;
    font-size: 15px;
  }

  #inside .ewc-card p {
    width: 100%;
    flex: 1 1 auto;
    margin: 0;
  }

  .ewc-proof-card {
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 24px;
    background: rgba(255, 255, 255, 0.04);
  }

  #process .ewc-proof-grid .ewc-proof-card .ewc-pill {
    padding: 0;
    margin-bottom: 6px;
    border: 0;
    border-radius: 0;
    background: transparent;
    color: var(--ewc-accent-2);
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 0.16em;
    line-height: 1.2;
    text-transform: uppercase;
    box-shadow: none;
  }

  .ewc-credibility {
    display: grid;
    grid-template-columns: minmax(0, 0.92fr) minmax(0, 1.08fr);
    gap: 22px;
    align-items: stretch;
  }

  .ewc-credibility-media {
    overflow: hidden;
    border-radius: 28px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: rgba(255, 255, 255, 0.04);
  }

  .ewc-credibility-copy {
    padding: 34px 32px;
    border-radius: 28px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(255, 255, 255, 0.08);
  }

  .ewc-credibility-copy h2 {
    font-size: clamp(34px, 4vw, 52px);
    max-width: 11ch;
  }

  .ewc-credibility-copy p {
    margin: 18px 0 0;
    color: var(--ewc-muted);
    line-height: 1.75;
    font-size: 16px;
  }

  .ewc-credibility-list {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 14px;
    margin-top: 26px;
  }

  .ewc-credibility-list div {
    padding: 16px 18px;
    border-radius: 20px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(255, 255, 255, 0.08);
    color: var(--ewc-soft);
    font-size: 14px;
    line-height: 1.6;
  }

  .ewc-case-card-meta {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-bottom: 16px;
  }

  .ewc-case-card-list,
  .ewc-price-list {
    margin: 18px 0 0;
    padding: 0;
    list-style: none;
    display: grid;
    gap: 12px;
  }

  .ewc-case-card-list li,
  .ewc-price-list li {
    color: var(--ewc-soft);
    line-height: 1.6;
    font-size: 14px;
  }

  .ewc-case-card-list span,
  .ewc-price-list span {
    color: var(--ewc-muted);
  }

  .ewc-proof-cta {
    margin-top: 24px;
  }

  .ewc-case-preview-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .ewc-inline-proof {
    display: grid;
    gap: 16px;
    margin-top: 24px;
  }

  .ewc-inline-proof-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 16px;
    width: 100%;
  }

  .ewc-inline-proof-card {
    overflow: hidden;
    border-radius: 24px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: rgba(255, 255, 255, 0.04);
  }

  .ewc-inline-proof-card img {
    display: block;
    width: 100%;
    height: auto;
    border-radius: 8px;
  }

  .ewc-inline-proof-card span {
    display: block;
    padding: 14px 16px 16px;
    color: var(--ewc-soft);
    font-size: 13px;
    letter-spacing: 0.12em;
    text-transform: uppercase;
  }

  .ewc-inline-proof-caption {
    margin: 0;
    color: var(--ewc-muted);
    font-size: 15px;
    line-height: 1.7;
  }

  #pricing .ewc-pricing-grid {
    grid-template-columns: repeat(4, minmax(0, 1fr));
    align-items: stretch;
  }

  .ewc-price-card {
    display: grid;
    grid-template-rows: 40px minmax(76px, auto) 54px 22px minmax(120px, auto) auto 1fr auto;
    min-height: 644px;
    padding: 30px;
    align-items: start;
    gap: 14px;
  }

  #pricing .ewc-price-card h3 {
    grid-row: 2;
    min-height: 0;
    display: flex;
    align-items: flex-start;
  }

  .ewc-price-card .ewc-eyebrow {
    margin-bottom: 0;
    min-height: 34px;
    padding: 9px 12px;
    font-size: 11px;
    line-height: 1;
    letter-spacing: 0.12em;
  }

  .ewc-price-top {
    display: flex;
    grid-row: 1;
    align-items: center;
    justify-content: flex-start;
    gap: 10px;
    min-height: 0;
    flex-wrap: nowrap;
  }

  .ewc-price-badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 9px 12px;
    border-radius: 999px;
    border: 1px solid rgba(107, 241, 211, 0.24);
    background: rgba(107, 241, 211, 0.12);
    color: #d6fff7;
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    white-space: nowrap;
    box-shadow: 0 10px 22px rgba(56, 140, 126, 0.16);
    min-height: 34px;
  }

  .ewc-price-card-highlight {
    border-color: rgba(138, 182, 255, 0.24);
    box-shadow: 0 30px 70px rgba(0, 0, 0, 0.28), 0 0 0 1px rgba(138, 182, 255, 0.14);
  }

  .ewc-price-card-premium {
    border-color: rgba(107, 241, 211, 0.2);
    background:
      radial-gradient(circle at top right, rgba(107, 241, 211, 0.08), transparent 34%),
      linear-gradient(180deg, rgba(255, 255, 255, 0.1) 0%, rgba(255, 255, 255, 0.04) 100%);
  }

  .ewc-price-value {
    display: inline-flex;
    grid-row: 3;
    align-items: flex-end;
    gap: 4px;
    flex-wrap: nowrap;
    margin-top: 0;
    min-height: 0;
    font-size: clamp(34px, 5vw, 54px);
    line-height: 1;
    letter-spacing: -0.05em;
    color: var(--ewc-text);
    white-space: nowrap;
  }

  .ewc-price-period {
    display: inline-flex;
    align-items: flex-end;
    margin-left: 0;
    padding-bottom: 4px;
    font-size: 18px;
    line-height: 1;
    letter-spacing: 0;
    color: var(--ewc-muted);
    white-space: nowrap;
  }

  .ewc-price-note {
    grid-row: 4;
    display: flex;
    align-items: flex-start;
    margin-top: 0;
    color: var(--ewc-muted);
    font-size: 14px;
  }

  .ewc-price-note:empty::before {
